    align-items: center;
    gap: 2rem;
    padding: 6rem 5%;
    background-color: #0e0e14;
}

.duality-card {
    flex: 1;
    max-width: 500px;
    background: var(--bg-card);
    border-radius: 15px;
    overflow: hidden;
    transition: transform 0.3s ease;
    border: 1px solid rgba(255,255,255,0.05);
}

.duality-card:hover {
    transform: translateY(-10px);
    border-color: var(--accent-gold);
}

.card-img img {
    width: 100%;
    height: 400px;
    object-fit: cover;
    filter: grayscale(30%);
    transition: filter 0.3s ease;
}

.duality-card:hover .card-img img {
    filter: grayscale(0%);
}

.card-content {
    padding: 2rem;
}

.card-content h3 {
    font-family: var(--font-heading);
    font-size: 1.8rem;
    margin-bottom: 1rem;
    color: var(--accent-cyan);
}

.card-content p {
    color: var(--text-muted);
}

.synthesis-bridge {
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 150px;
    text-align: center;
}

.bridge-circle {
    width: 60px;
    height: 60px;
    border: 2px solid var(--accent-gold);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
    color: var(--accent-gold);
    margin-bottom: 1rem;
    background: var(--bg-dark);
}

.synthesis-bridge h4 {
    font-size: 0.8rem;
    letter-spacing: 3px;
    color: var(--accent-gold);
}

/* Forge Section */
.forge {
    padding: 8rem 5%;
    background: linear-gradient(to bottom, #0e0e14, var(--bg-dark));
}

.forge-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4rem;
    align-items: center;
}

.forge-text h2 {
    font-family: var(--font-heading);
    font-size: 3rem;
    margin-bottom: 1.5rem;
}

.forge-text p {
    color: var(--text-muted);
    margin-bottom: 2rem;
    font-size: 1.1rem;
}

.feature-list {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.feature-item {
    padding-left: 1rem;
    border-left: 2px solid var(--accent-cyan);
    color: var(--text-main);
}

.forge-img-container {
    position: relative;
}

.forge-img {
    width: 100%;
    border-radius: 20px;
    box-shadow: 0 20px 50px rgba(0,0,0,0.5);
    border: 1px solid rgba(255,255,255,0.1);
    transition: transform 0.5s ease;
}

.forge-img:hover {
    transform: scale(1.02);
}

/* Footer */
footer {
    padding: 4rem 5%;
    border-top: 1px solid rgba(255,255,255,0.05);
    text-align: center;
}

.footer-logo {
    font-family: var(--font-heading);
    font-size: 1.5rem;
    color: var(--accent-gold);
    margin-bottom: 1rem;
}

.footer-content p {
    font-size: 0.8rem;
    color: var(--text-muted);
}

/* Mobile Responsive */
@media (max-width: 992px) {
    .duality {
        flex-direction: column;
    }
    .synthesis-bridge {
        margin: 2rem 0;
    }
    .forge-grid {
        grid-template-columns: 1fr;
        text-align: center;
    }
    .feature-list {
        align-items: center;
    }
    .hero-content h1 {
        font-size: 3rem;
    }
}
